import Page from 'components/Page';
import React from 'react';
import Searchable from 'react-select';
import {
  Button,
  Card,
  CardBody,
  CardHeader,
  Col,
  Form,
  FormFeedback,
  FormGroup,
  FormText,
  Input,
  Label,
  Row,
  Alert,
  Table,
} from 'reactstrap';
import states from "../api/states";
import yearsofex from "../api/yearsofex";
import { newEntryPerformance, findEntryPerformances,findStudents, findSubjectsByStudent,findAssessments } from "../api/api";
import AsyncStorage from '@callstack/async-storage';
import conf from "../api/config";
import PageSpinner from 'components/PageSpinner';
import MUIDataTable from "mui-datatables";
import CustomToolbarSelectStudEntries from "../components/CustomToolbarSelectStudEntries";
class EntriesPage extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
          student : 'nn',
          subject : 'nn',
          group : 'nn',
          mark : '',
          remark : '',
          xtoken:'',
          msg: '',
          error: '',
          preload:false,
          downloadFile:true,
          data: [],
          students: [],
          subjects: [],
          groups: [],
          selectableStudents:[],
        };
        AsyncStorage.getItem(conf.secret)
        .then((results) => {
          if( results !== null )
          {
            let obje_results = JSON.parse(results);
            this.setState({
              ...this.state,
              xtoken : obje_results.user.token,
            });
            findEntryPerformances(obje_results.user.token).then((response) => {
                this.setState({
                    ...this.state,
                    data:response.data,
                });
            }).catch((respError) => {});
            findStudents(obje_results.user.token).then((response) => {
                this.setState({
                    ...this.state,
                    students:response.data,
                });
                this.searchableStudentList(response.data);
            }).catch((respError) => {});
            
            findAssessments(obje_results.user.token).then((response) => {
              this.setState({
                  ...this.state,
                  groups:response.data,
              });
          }).catch((respError) => {});
          }
        })
        .catch((error) => {
          console.log('storage error', error);
        });
    }
    componentDidMount() {
    }

    rerenderParentCallback = () => {
      findEntryPerformances (this.state.xtoken).then((response) => {
        this.setState({
            ...this.state,
            data:response.data,
        });
      }).catch((respError) => {
      });
    }
    searchableStudentList = (input) => {
        let studentOpts = [];
        
        input.forEach( function(x){
          let lbl = x.fname + ' - ' + x.lname + ':' + x.admission;
          let entry = { value: x.id, label: lbl };
          studentOpts.push(entry);
        });
        this.setState({
          ...this.state,
          selectableStudents:studentOpts,
        });
      }
    handleStudentInput = selectedPar => {
        const v = selectedPar.value.toString();
        findSubjectsByStudent(this.state.xtoken, v).then((response) => {
            this.setState({
                ...this.state, 
                subjects: response.data,
                student: v,
            });
        }).catch((err) => {
            this.setState({
                ...this.state, 
                student: v,
            });
        });
    }
    handleSubjectInput = (event) => {
        const v = event.target.value;
        this.setState({
          ...this.state, 
          subject: v,
      });
    }
    handleGroupInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, group: v,});
    }
    handleMarkInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, mark: v,});
    }
    handleRemarkInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, remark: v,});
    }
    handleSaveChanges = () => {
        // console.log('so far', this.state);
        this.setState({
          ...this.state,
          preload:true,
        });
        newEntryPerformance(this.state.xtoken, this.state)
        .then((response) => {
            // console.log('so_far', response);
            if( response.status === 200)
            {
                this.setState({
                    ...this.state,
                    mark : '',
                    remark:'',
                    msg: response.message,
                    data: response.data,
                    error: '',
                    preload:false,
                });
            }
            else
            {
                this.setState({
                    ...this.state,
                    error: response.message,
                    msg: '',
                    preload:false,
                });
            }
        })
        .catch((error) => {
            this.setState({
                ...this.state,
                error: 'Connection error occured',
                preload:false,
            });
            console.log('error', error);
        });
    }
    render() {
        const columns = [
            {
                name: 'Id',
                options: {
                display: false
                }
            },
            'Term/Year',
            {
                name: 'Admission',
                options: {
                  display: false
                }
            },
            'Student',
            'Form',
            'Stream',
            'Subject',
            'Assessment',
            'Score',
            'Grade',
            'Remarks',
        ];

        const data2 = () => {
          let rtn = [];
          this.state.data.map(item => {
            rtn.push([
                item.id,
                item.ylabel,
                item.admlabel,
                item.slabel,
                item.flabel,
                item.streamlabel,
                item.sublabel,
                item.alabel,
                item.mark,
                item.grade,
                item.remark,
            ]);
          });
          return rtn;
        }
      
        const options = {
            filter: true,
            selectableRows: 'single',
            selectableRowsOnClick:true,
            filterType: 'dropdown',
            responsive: 'vertical',
            draggableColumns: {
              enabled: true
            },
            rowsPerPage: 5,
            selectToolbarPlacement: 'replace',
            customToolbarSelect: (selectedRows, displayData, setSelectedRows) => (
              <CustomToolbarSelectStudEntries rerenderParentCallback={this.rerenderParentCallback} selectedRows={selectedRows} displayData={displayData} setSelectedRows={setSelectedRows}  originalData={this.state.data} Xtoken={this.state.xtoken}/>
            ),
            downloadOptions: {
                filename: 'school-data-excel-format.csv',
                separator: ';',
                filterOptions: {
                  useDisplayedColumnsOnly: true,
                  useDisplayedRowsOnly: true,
                }
            },
            onDownload: (buildHead, buildBody, columns, data2) => {
              if (this.state.downloadFile) {
                let val= `${buildHead(columns)}${buildBody(data2)}`.trim();
                return val;
              }
      
              return false;
            },
            onRowSelectionChange: (currentRowsSelected, allRows, rowsSelected) => {
              // console.log('currentRowsSelected', currentRowsSelected);
            },
            onRowsDelete: rowsDeleted => {
              // console.log(rowsDeleted, 'were deleted!');
            },
            onChangePage: numberRows => {
              // console.log(numberRows);
            },
            onSearchChange: searchText => {
              // console.log(searchText);
            },
            onColumnSortChange: (column, direction) => {
              // console.log(column, direction);
            },
            onViewColumnsChange: (column, action) => {
              // console.log(column, action);
            },
            onFilterChange: (column, filters) => {
              // console.log(column, filters);
            },
            onCellClick: (cellIndex, rowIndex) => {
              // console.log(cellIndex, rowIndex);
            },
            onRowClick: (rowData, rowState) => {
              // console.log(rowData, rowState);
            },
        };
      return (
        <Page title="Performance - Marks & Grades" breadcrumbs={[{ name: 'Marks & Grades', active: true }]}>
          <Row>
            <Col xl={12} lg={12} md={12}>
              <Card>
                <CardHeader>Mark Entry {this.state.preload && (<PageSpinner/>)} </CardHeader>
                {this.state.error.length > 0 && (
                    <Alert color="danger">{this.state.error}</Alert>
                )}
                {this.state.msg.length > 0 && (
                    <Alert color="success">{this.state.msg}</Alert>
                )}
              </Card>
            </Col>
          </Row>

          <Row>
            <Col xl={4} lg={12} md={12}>
              <Card>
                <CardBody>
                <Form>
                    <FormGroup>
                      <Label for="exampleEmail">Student*</Label>
                      <Searchable defaultValue={this.state.student} onChange={this.handleStudentInput} options={this.state.selectableStudents}/>
                    </FormGroup>
                    <FormGroup>
                      <Label for="exampleEmail">Applicable Subject*</Label>
                      <Input onChange={this.handleSubjectInput} value={this.state.subject} defaultValue={this.state.subject} type="select" name="frm">
                        <option value="nn" disabled={true}>Select subject</option>
                        {this.state.subjects.map((stt, idx) => (
                            <option value={stt.id}>{stt.label}</option>
                        ))}
                      </Input>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
            <Col xl={4} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>  
                    <FormGroup>
                      <Label for="exampleEmail">Assessment*</Label>
                      <Input onChange={this.handleGroupInput} value={this.state.group} defaultValue={this.state.group} type="select" name="frm">
                        <option value="nn" disabled={true}>Select assessment</option>
                        {this.state.groups.map((stt, idx) => (
                            <option value={stt.id}>{stt.name}</option>
                        ))}
                      </Input>
                    </FormGroup>   
                    <FormGroup>
                      <Label for="exampleSelect">Marks*</Label>
                      <Input onChange={this.handleMarkInput}
                        type="number" 
                        value={this.state.mark}
                        name="frm"
                        placeholder=""
                      />
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
            <Col xl={4} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>
                    <FormGroup>
                      <Label for="exampleSelect">Remarks*</Label>
                      <Input onChange={this.handleRemarkInput}
                        type="text" 
                        value={this.state.remark}
                        name="frm"
                        maxLength="16"
                        placeholder=""
                      />
                    </FormGroup> 
                    <FormGroup check row>
                      <Col sm={{ size: 10, offset: 2 }}>
                        <Button type="button" onClick={this.handleSaveChanges}>Add score</Button>
                      </Col>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
          </Row>

          <Row>
            <Col xl={12} lg={12} md={12}>
              <Card>
                <CardBody>
                    <MUIDataTable title={'Student Marks & Grades'}
                    data={this.state.data.map(item => {
                      return [
                        item.id,
                        item.ylabel,
                        item.admlabel,
                        item.slabel,
                        item.flabel,
                        item.streamlabel,
                        item.sublabel,
                        item.alabel,
                        item.mark,
                        item.grade,
                        item.remark,
                      ]
                    })} columns={columns} options={options} />
                </CardBody>
              </Card>
            </Col>
          </Row>
    
        </Page>
      );
    }
}
export default EntriesPage;
